import{_ as t,o as n,c as a,a2 as o}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"Goose Architecture Analysis","description":"","frontmatter":{"title":"Goose Architecture Analysis","status":"complete"},"headers":[],"relativePath":"research/agents/goose/index.md","filePath":"research/agents/goose/index.md"}'),s={name:"research/agents/goose/index.md"};function r(i,e,l,c,p,d){return n(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="goose" tabindex="-1">Goose <a class="header-anchor" href="#goose" aria-label="Permalink to &quot;Goose&quot;">​</a></h1><blockquote><p>An open-source, on-machine AI coding agent by Block (formerly Square) that automates engineering tasks end-to-end, built on MCP (Model Context Protocol) for extensibility.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Goose is a local-first AI agent developed by <strong>Block, Inc.</strong> (formerly Square) and released as open source under the Apache 2.0 license. Unlike cloud-hosted coding assistants, Goose runs entirely on the developer&#39;s machine, executing shell commands, editing files, and orchestrating complex workflows autonomously.</p><p>The project is written primarily in <strong>Rust</strong> (core agent, server, CLI) with a <strong>TypeScript/Electron</strong> desktop UI. It ships as both a CLI tool and a desktop application, with shared configuration between the two interfaces.</p><p><strong>Key characteristics:</strong></p><ul><li><strong>MCP-native architecture</strong>: Extensions are MCP (Model Context Protocol) servers, making Goose a first-class MCP client that can connect to any MCP-compatible tool ecosystem</li><li><strong>Provider-agnostic</strong>: Supports 30+ LLM providers (Anthropic, OpenAI, Google, Azure, Bedrock, Ollama, and many more)</li><li><strong>Multi-model</strong>: Supports configuring different models for primary reasoning vs. fast operations</li><li><strong>Enterprise-oriented</strong>: Built by Block with enterprise needs in mind — permission controls, access restrictions, custom distributions, and CI/CD support</li><li><strong>Extensible by design</strong>: Plugin system based entirely on MCP, with built-in extensions, platform extensions, external stdio/HTTP extensions, and even inline Python extensions</li></ul><h2 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h2><ul><li><strong>URL</strong>: <a href="https://github.com/block/goose" target="_blank" rel="noreferrer">https://github.com/block/goose</a></li><li><strong>Language</strong>: Rust (core), TypeScript (desktop UI)</li><li><strong>License</strong>: Apache 2.0</li><li><strong>Current version</strong>: 1.28.0 (as of research date)</li><li><strong>Stars</strong>: ~15k+</li><li><strong>Organization</strong>: Block, Inc.</li></ul><h2 id="architecture-summary" tabindex="-1">Architecture Summary <a class="header-anchor" href="#architecture-summary" aria-label="Permalink to &quot;Architecture Summary&quot;">​</a></h2><p>Goose is organized as a Rust workspace with 8 crates:</p><table tabindex="0"><thead><tr><th>Crate</th><th>Purpose</th></tr></thead><tbody><tr><td><code>goose</code></td><td>Core library — agent loop, providers, config, context management, MCP client</td></tr><tr><td><code>goose-cli</code></td><td>CLI binary (<code>goose</code> command)</td></tr><tr><td><code>goose-server</code></td><td>HTTP/API server (Axum-based)</td></tr><tr><td><code>goose-mcp</code></td><td>Built-in MCP server implementations</td></tr><tr><td><code>goose-acp</code></td><td>Agent Communication Protocol support</td></tr><tr><td><code>goose-acp-macros</code></td><td>Proc macros for ACP</td></tr><tr><td><code>goose-test</code></td><td>Test utilities</td></tr><tr><td><code>goose-test-support</code></td><td>Test support infrastructure</td></tr></tbody></table><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│  UI Layer (Desktop / CLI / Text TUI)    │</span></span>
<span class="line"><span>└──────────────┬──────────────────────────┘</span></span>
<span class="line"><span>               │ HTTP API</span></span>
<span class="line"><span>┌──────────────▼──────────────────────────┐</span></span>
<span class="line"><span>│  goose-server (Axum)                    │</span></span>
<span class="line"><span>│  Routes → Session → Agent               │</span></span>
<span class="line"><span>└──────────────┬──────────────────────────┘</span></span>
<span class="line"><span>               │</span></span>
<span class="line"><span>┌──────────────▼──────────────────────────┐</span></span>
<span class="line"><span>│  Agent (core loop)                      │</span></span>
<span class="line"><span>│  • Stream LLM responses                 │</span></span>
<span class="line"><span>│  • Parse tool calls                     │</span></span>
<span class="line"><span>│  • Permission &amp; security inspection     │</span></span>
<span class="line"><span>│  • Dispatch to ExtensionManager         │</span></span>
<span class="line"><span>│  • Context management &amp; compaction      │</span></span>
<span class="line"><span>└──────┬──────────────┬───────────────────┘</span></span>
<span class="line"><span>       │              │</span></span>
<span class="line"><span>┌──────▼──────┐ ┌─────▼──────────────────┐</span></span>
<span class="line"><span>│  Provider   │ │  ExtensionManager      │</span></span>
<span class="line"><span>│  (LLM API)  │ │  (MCP client router)   │</span></span>
<span class="line"><span>│  30+ impls  │ │  Platform | Builtin |  │</span></span>
<span class="line"><span>└─────────────┘ │  Stdio | HTTP | Python │</span></span>
<span class="line"><span>                └────────────────────────┘</span></span></code></pre></div><h2 id="key-components" tabindex="-1">Key Components <a class="header-anchor" href="#key-components" aria-label="Permalink to &quot;Key Components&quot;">​</a></h2><h3 id="agent-loop" tabindex="-1">Agent Loop <a class="header-anchor" href="#agent-loop" aria-label="Permalink to &quot;Agent Loop&quot;">​</a></h3><p>The core agent loop lives in <code>crates/goose/src/agents/agent.rs</code> (~97KB). It implements a streaming reply loop: prepare context → call LLM → parse tool calls → inspect permissions → dispatch tools → collect results → loop. See <a href="./agentic-loop.html">agentic-loop.md</a> for details.</p><h3 id="extension-system-mcp" tabindex="-1">Extension System (MCP) <a class="header-anchor" href="#extension-system-mcp" aria-label="Permalink to &quot;Extension System (MCP)&quot;">​</a></h3><p>All tool functionality is provided through extensions, which are MCP servers. Goose supports 7 extension transport types: Platform (in-process), Builtin (DuplexStream MCP), Stdio (child process), StreamableHttp (remote), InlinePython, Frontend, and SSE (deprecated). See <a href="./tool-system.html">tool-system.md</a> for details.</p><h3 id="provider-system" tabindex="-1">Provider System <a class="header-anchor" href="#provider-system" aria-label="Permalink to &quot;Provider System&quot;">​</a></h3><p>Goose abstracts LLM access behind a <code>Provider</code> trait with 30+ implementations. It supports multi-model configuration, prompt caching (for Claude), and a &quot;toolshim&quot; mode for models without native tool-calling. See <a href="./architecture.html">architecture.md</a> for details.</p><h3 id="context-management" tabindex="-1">Context Management <a class="header-anchor" href="#context-management" aria-label="Permalink to &quot;Context Management&quot;">​</a></h3><p>Automatic compaction at 80% of context window, background tool-pair summarization, and emergency compaction on context overflow errors. See <a href="./context-management.html">context-management.md</a> for details.</p><h2 id="benchmark-performance" tabindex="-1">Benchmark Performance <a class="header-anchor" href="#benchmark-performance" aria-label="Permalink to &quot;Benchmark Performance&quot;">​</a></h2><h3 id="terminal-bench-2-0" tabindex="-1">Terminal-Bench 2.0 <a class="header-anchor" href="#terminal-bench-2-0" aria-label="Permalink to &quot;Terminal-Bench 2.0&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Rank</th><th>Score</th></tr></thead><tbody><tr><td>Claude Opus 4.5</td><td>#44</td><td>54.3%</td></tr><tr><td>Claude Sonnet 4.5</td><td>#61</td><td>43.1%</td></tr></tbody></table><h3 id="terminal-bench-1-0" tabindex="-1">Terminal-Bench 1.0 <a class="header-anchor" href="#terminal-bench-1-0" aria-label="Permalink to &quot;Terminal-Bench 1.0&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Rank</th><th>Score</th></tr></thead><tbody><tr><td>claude-opus-4</td><td>#17</td><td>45.3%</td></tr></tbody></table><h2 id="interesting-patterns" tabindex="-1">Interesting Patterns <a class="header-anchor" href="#interesting-patterns" aria-label="Permalink to &quot;Interesting Patterns&quot;">​</a></h2><ol><li><strong>MCP as the universal extension interface</strong>: Everything is an MCP server — built-in tools, platform features, external plugins, even inline Python scripts</li><li><strong>Multi-layered tool inspection</strong>: Security → Adversary → Permission → Repetition inspection pipeline before any tool executes</li><li><strong>MOIM (Model-Oriented Information Management)</strong>: Dynamic context injection from extensions into the conversation each turn</li><li><strong>Tool-pair summarization</strong>: Background task that summarizes old tool request/response pairs to save context tokens</li><li><strong>Recipe system</strong>: Automated task execution with success criteria, retry logic, and conversation reset</li><li><strong>Subagent delegation</strong>: The &quot;Summon&quot; extension can delegate tasks to subagents with isolated contexts</li><li><strong>Enterprise permission modes</strong>: Autonomous, Manual Approval, Smart Approval, and Chat-only modes</li></ol><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://github.com/block/goose" target="_blank" rel="noreferrer">GitHub Repository</a></li><li><a href="https://block.github.io/goose/" target="_blank" rel="noreferrer">Documentation</a></li><li><a href="./architecture.html">Architecture Deep Dive</a></li><li><a href="./agentic-loop.html">Agent Loop Analysis</a></li><li><a href="./tool-system.html">Tool System</a></li><li><a href="./context-management.html">Context Management</a></li><li><a href="./unique-patterns.html">Unique Patterns</a></li><li><a href="./benchmarks.html">Benchmarks</a></li><li><a href="./references.html">All References</a></li></ul>`,31)])])}const u=t(s,[["render",r]]);export{m as __pageData,u as default};
